<!DOCTYPE html>
<html lang="en">

@include("utility.head")

<style>
    h1,
    h2 {
        font-weight: 600;
    }
</style>

<body>
    @include("utility.navbar")

    @if(session("message"))
    <div class="modal fade" id="exampleModal" tabindex="-1" aria-labelledby="exampleModalLabel" aria-hidden="true">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="bg-light modal-header">
                    <h1 class=" modal-title fs-5" id="exampleModalLabel">Changed successfully! ✅</h1>
                    <button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Close"></button>
                </div>
                <div class="modal-body">
                    {{ session("message") }}
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-primary" data-bs-dismiss="modal">Close</button>
                </div>
            </div>
        </div>
    </div>

    <script>
        let myModal = new bootstrap.Modal(document.getElementById('exampleModal'), {});
        myModal.show();
    </script>
    @endif

    <div class="container">
        <div class="text-center">
            <div style="max-width: 500px;" class="pt-4 pb-3 mx-auto">
                <p class="mb-1">Hello {{ $user }}, welcome to</p>
                <h1 style="font-weight: 700;">Fajar E-Maintenance</h1>
                <p class="mb-3">Lorem ipsum dolor sit amet consectetur adipisicing elit. A quidem quia ducimus ipsam, reprehenderit libero?</p>
